# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql

# Database settings
rds_host = "your_rds_host"
username = "your_username"
password = "your_password"
database = "your_database"

def lambda_handler(event, context):
    # Connect to the database
    connection = pymysql.connect(host=rds_host,
                                 user=username,
                                 password=password,
                                 db=database,
                                 cursorclass=pymysql.cursors.DictCursor)

    search_params = event.get('queryStringParameters', {})
    query = "SELECT * FROM products WHERE 1=1"
    parameters = []
    
    if 'name' in search_params:
        query += " AND name LIKE %s"
        parameters.append(f"%{search_params['name']}%")
    
    if 'category' in search_params:
        query += " AND category = %s"
        parameters.append(search_params['category'])
    
    if 'min_price' in search_params:
        query += " AND price >= %s"
        parameters.append(search_params['min_price'])
    
    if 'max_price' in search_params:
        query += " AND price <= %s"
        parameters.append(search_params['max_price'])

    try:
        with connection.cursor() as cursor:
            cursor.execute(query, parameters)
            results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'body': json.dumps(results)
        }

    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
    
    finally:
        connection.close()